public:
    int countLargestGroup(int n) {
        int freq[37] = {0};
        for (int i = 1; i <= n; ++i) {
            int sum = 0, x = i;
            while (x) { sum += x % 10; x /= 10; }
            ++freq[sum];
        }
        int maxSize = 0, count = 0;
        for (int s = 1; s <= 36; ++s) {
            if (freq[s] > maxSize) { maxSize = freq[s]; count = 1; }
            else if (freq[s] == maxSize) ++count;
        }
        return count;
    }
};
